import { useState, useEffect, useMemo, useRef } from "react";
import { db, isConfigured } from "./db";
import { enablePush } from "./push";

/* ============================================================
   Cancún Cash — a family vacation spending tracker
   Flow: Who → How they paid → What for → How much (+tip) → Save
   Totals + transaction log persist across sessions via window.storage
   ============================================================ */

const MEMBERS = [
  { id: "Dad", color: "#1E88C7", soft: "#D6ECF9", photo: "data:image/jpeg;base64,", hatPhoto: "data:image/jpeg;base64," },
  { id: "Mom", color: "#FF5E9C", soft: "#FFE0EE", photo: "data:image/jpeg;base64,", hatPhoto: "data:image/jpeg;base64," },
  { id: "Carter", color: "#16A34A", soft: "#D7F4E3", photo: "data:image/jpeg;base64,", hatPhoto: "data:image/jpeg;base64," },
  { id: "Jett", color: "#FF7A1A", soft: "#FFE7D2", photo: "data:image/jpeg;base64,", hatPhoto: "data:image/jpeg;base64," },
];

const PINS = { Dad: "9324", Mom: "0829", Carter: "2100", Jett: "9981" };

const METHODS = [
  { id: "Cash",      icon: "💵", sub: "Family cash" },
  { id: "Card",      icon: "💳", sub: "Family card" },
  { id: "Own Money",   icon: "🐷", sub: "Their own" },
  { id: "Room Charge", icon: "🏨", sub: "Bills to room" },
];

const CATEGORIES = [
  { id: "Drinks",         icon: "🍹", color: "#0FB5BC" },
  { id: "Food",           icon: "🍔", color: "#FF8A3C" },
  { id: "Family Lunch",   icon: "🥗", color: "#16A34A" },
  { id: "Family Dinner",  icon: "🍽️", color: "#FF5E9C" },
  { id: "Excursions",     icon: "🚤", color: "#1E88C7" },
  { id: "Souvenirs",      icon: "🎁", color: "#9B6BFF" },
  { id: "Tips",           icon: "🤝", color: "#00B8A9" },
  { id: "Transportation", icon: "🚕", color: "#FFC93C" },
  { id: "Entertainment",  icon: "🎭", color: "#FF6F61" },
  { id: "Golf",           icon: "⛳", color: "#2BB673" },
  { id: "Amenities",      icon: "🛁", color: "#7C5CFF" },
  { id: "Room Service",   icon: "🛎️", color: "#FF9551" },
  { id: "Other",          icon: "✏️", color: "#5B7B82" },
];

const C = {
  sand: "#EAF3FB",
  sandDeep: "#CFE6F7",
  ink: "#0A2A4A",
  inkSoft: "#5577A0",
  white: "#FFFFFF",
  ocean: "#1E73C8",
  oceanDeep: "#0B4A8A",
  coral: "#FF6F61",
  sun: "#FFC93C",
  pink: "#FF5E9C",
  line: "#D4E6F5",
};

const emptyDraft = () => ({
  spender: null, method: null, category: null,
  notes: "", amountCents: 0, tipCents: 0,
});

const fmt = (c) => "$" + (c / 100).toFixed(2);
const catOf = (id) => CATEGORIES.find((c) => c.id === id) || CATEGORIES[CATEGORIES.length - 1];
const memOf = (id) => MEMBERS.find((m) => m.id === id) || { color: C.ocean, soft: C.sandDeep };
const ROOMS = ["Lance/Lori Room", "Carter/Jett Room"];
const roomFor = (spender) => (spender === "Carter" || spender === "Jett") ? "Carter/Jett Room" : "Lance/Lori Room";
const when = (ts) =>
  new Date(ts).toLocaleString(undefined, { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });

export default function App() {
  const [transactions, setTransactions] = useState([]);
  const [view, setView] = useState("log"); // 'log' | 'totals'
  const [step, setStep] = useState("spender"); // spender | method | category | amount | saved
  const [draft, setDraft] = useState(emptyDraft());
  const [activeField, setActiveField] = useState("amount"); // amount | tip
  const [showTip, setShowTip] = useState(false);
  const [lastSaved, setLastSaved] = useState(null);
  const [unlocked, setUnlocked] = useState({});
  const [pinFor, setPinFor] = useState(null);
  const [adminPin, setAdminPin] = useState(false);

  const [toast, setToast] = useState(null);
  const [alertsOn, setAlertsOn] = useState(false);
  const ownIds = useRef(new Set());

  const flash = (msg, ms = 4000) => { setToast(msg); window.clearTimeout(flash._t); flash._t = window.setTimeout(() => setToast(null), ms); };

  useEffect(() => {
    if (!isConfigured) return;
    db.fetchAll().then(setTransactions).catch(() => {});
    const unsub = db.subscribe((evt) => {
      setTransactions((cur) => {
        if (evt.type === "INSERT") {
          if (cur.some((t) => t.id === evt.row.id)) return cur;
          if (!ownIds.current.has(evt.row.id)) {
            flash(`${evt.row.spender} logged ${evt.row.category} · ${fmt(evt.row.amountCents + evt.row.tipCents)}`);
          }
          return [evt.row, ...cur];
        }
        if (evt.type === "UPDATE") return cur.map((t) => (t.id === evt.row.id ? evt.row : t));
        if (evt.type === "DELETE") return cur.filter((t) => t.id !== evt.id);
        return cur;
      });
    });
    return () => unsub();
  }, []);

  const handleAlerts = async () => {
    const ok = await enablePush();
    setAlertsOn(ok);
    flash(ok ? "🔔 Alerts on for this phone" : "Couldn't turn on alerts — check the home-screen step", 4500);
  };

  /* ---------- actions ---------- */
  const reset = () => {
    setDraft(emptyDraft());
    setStep("spender");
    setActiveField("amount");
    setShowTip(false);
  };

  const press = (key) => {
    setDraft((d) => {
      const field = activeField === "tip" ? "tipCents" : "amountCents";
      let v = d[field];
      if (key === "back") v = Math.floor(v / 10);
      else if (key === "clear") v = 0;
      else if (key === "00") v = Math.min(v * 100, 99999999);
      else v = Math.min(v * 10 + Number(key), 99999999);
      return { ...d, [field]: v };
    });
  };

  const save = async () => {
    const payload = {
      spender: draft.spender,
      method: draft.method,
      room: draft.method === "Room Charge" ? roomFor(draft.spender) : null,
      category: draft.category,
      notes: draft.notes.trim(),
      amountCents: draft.amountCents,
      tipCents: draft.tipCents,
    };
    setLastSaved({ ...payload, ts: Date.now() });
    setStep("saved");
    try {
      const row = await db.add(payload);
      if (row) {
        ownIds.current.add(row.id);
        setTransactions((cur) => (cur.some((t) => t.id === row.id) ? cur : [row, ...cur]));
        db.notify(
          `${payload.spender} spent ${fmt(payload.amountCents + payload.tipCents)}`,
          `${payload.category}${payload.notes ? " · " + payload.notes : ""} · ${payload.method}${payload.room ? " → " + payload.room : ""}`
        );
      }
    } catch (e) { /* offline: the entry still shows locally */ }
  };

  const deleteTx = (id) => {
    setTransactions((cur) => cur.filter((t) => t.id !== id));
    db.remove(id).catch(() => {});
  };

  const pickSpender = (id) => {
    if (unlocked[id]) { setDraft((d) => ({ ...d, spender: id })); setStep("method"); }
    else setPinFor(id);
  };
  const onPinSuccess = () => {
    const id = pinFor;
    setUnlocked((u) => ({ ...u, [id]: true }));
    setDraft((d) => ({ ...d, spender: id }));
    setStep("method");
    setPinFor(null);
  };
  const openAdmin = () => setAdminPin(true);
  const editTx = (id, patch) => {
    const current = transactions.find((t) => t.id === id);
    if (!current) return;
    const updated = { ...current, ...patch };
    updated.room = updated.method === "Room Charge" ? roomFor(updated.spender) : null;
    setTransactions((cur) => cur.map((t) => (t.id === id ? updated : t)));
    db.update(id, updated)
      .then(() => flash("Saved \u2713", 1500))
      .catch((e) => flash("Couldn't save \u2014 " + (e?.message || e), 6000));
  };

  const back = () => {
    if (step === "method") setStep("spender");
    else if (step === "category") setStep("method");
    else if (step === "amount") { setStep("category"); setShowTip(false); setActiveField("amount"); }
  };

  /* ---------- styles ---------- */
  const S = styles;

  /* ============================================================ */
  return (
    <div style={S.root}>
      <style>{css}</style>

      <div style={S.phone}>
        {toast && <div style={S.toast} role="status">{toast}</div>}
        {/* ---------- header ---------- */}
        <header style={S.header}>
          <div style={S.headerInner}>
            <div style={S.brandRow}>
              <span style={S.brandMark}>☀</span>
              <div>
                <div style={S.brand}>CunCa$h</div>
                <div style={S.brandSub}>Familia · Spend Tracker</div>
              </div>
            </div>
          </div>
          <Waves />
        </header>

        {/* ---------- tabs ---------- */}
        {view !== "admin" && (
        <nav style={S.tabs}>
          <button
            onClick={() => { setView("log"); }}
            style={{ ...S.tab, ...(view === "log" ? S.tabOn : {}) }}
          >＋ New spend</button>
          <button
            onClick={() => setView("totals")}
            style={{ ...S.tab, ...(view === "totals" ? S.tabOn : {}) }}
          >Totals</button>
        </nav>
        )}

        <main style={S.main}>
          {isConfigured && view !== "admin" && !alertsOn && (
            <button onClick={handleAlerts} style={S.alertsCta}>🔔 Turn on alerts on this phone</button>
          )}
          {!isConfigured ? (
            <SetupNeeded />
          ) : view === "admin" ? (
            <Admin transactions={transactions} onEdit={editTx} onDelete={deleteTx} onDone={() => { setView("log"); reset(); }} />
          ) : view === "totals" ? (
            <Totals transactions={transactions} onDelete={deleteTx} onAdd={() => { setView("log"); reset(); }} />
          ) : (
            <Log
              step={step} setStep={setStep}
              draft={draft} setDraft={setDraft}
              activeField={activeField} setActiveField={setActiveField}
              showTip={showTip} setShowTip={setShowTip}
              press={press} save={save} reset={reset} back={back}
              lastSaved={lastSaved} goTotals={() => setView("totals")}
              onAdmin={openAdmin} onPick={pickSpender}
            />
          )}
          {pinFor && (
            <PinModal
              member={pinFor}
              expected={PINS[pinFor]}
              onClose={() => setPinFor(null)}
              onResult={onPinSuccess}
            />
          )}
          {adminPin && (
            <PinModal
              member="Dad"
              expected={PINS.Dad}
              titleText="Admin · edit & delete"
              subText="Enter Dad's code to manage entries"
              onClose={() => setAdminPin(false)}
              onResult={() => { setAdminPin(false); setView("admin"); }}
            />
          )}
        </main>
      </div>
    </div>
  );
}

/* ============================================================
   LOG (the entry wizard)
   ============================================================ */
function Log(props) {
  const {
    step, setStep, draft, setDraft, activeField, setActiveField,
    showTip, setShowTip, press, save, reset, back, lastSaved, goTotals, onAdmin, onPick,
  } = props;
  const S = styles;

  const stepIndex = { spender: 0, method: 1, category: 2, amount: 3, saved: 4 }[step];

  return (
    <div>
      {/* breadcrumb / back */}
      {step !== "spender" && step !== "saved" && (
        <div style={S.crumbRow}>
          <button onClick={back} style={S.backBtn} aria-label="Go back">‹ Back</button>
          <div style={S.crumbChips}>
            {draft.spender && (
              <span style={S.spenderPill}>
                <span style={{ ...S.pillAvatar, borderColor: memOf(draft.spender).color }}>
                  <img src={memOf(draft.spender).hatPhoto || memOf(draft.spender).photo} alt={draft.spender} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                </span>
                {draft.spender}
              </span>
            )}
            {draft.method && <Chip color={C.oceanDeep}>{draft.method}</Chip>}
            {draft.category && <Chip color={catOf(draft.category).color}>{draft.category}</Chip>}
          </div>
          {draft.spender === "Dad" && (
            <button onClick={onAdmin} style={S.keyBtn} aria-label="Admin access" title="Admin edit">🔑</button>
          )}
        </div>
      )}

      {step !== "saved" && <Dots index={stepIndex} />}

      {/* ----- step 1: who ----- */}
      {step === "spender" && (
        <Section title="Who's spending?" sub="Tap a person to start a new entry">
          <div style={S.grid2}>
            {MEMBERS.map((m) => (
              <button
                key={m.id}
                onClick={() => onPick(m.id)}
                className="lift"
                style={{ ...S.personCard, background: m.soft, borderColor: m.color }}
              >
                <span style={{ ...S.avatar, borderColor: m.color, background: m.soft }}>
                  {m.photo
                    ? <img src={m.photo} alt={m.id} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    : <span style={{ color: "#fff" }}>{m.id[0]}</span>}
                </span>
                <span style={S.personName}>{m.id}</span>
              </button>
            ))}
          </div>
        </Section>
      )}

      {/* ----- step 2: how paid ----- */}
      {step === "method" && (
        <Section title="How'd they pay?" sub={`${draft.spender} is spending`}>
          <div style={S.stack}>
            {METHODS.map((m) => (
              <button
                key={m.id}
                onClick={() => { setDraft({ ...draft, method: m.id }); setStep("category"); }}
                className="lift"
                style={S.methodCard}
              >
                <span style={S.methodIcon}>{m.icon}</span>
                <span style={S.methodText}>
                  <span style={S.methodName}>{m.id}</span>
                  <span style={S.methodSub}>{m.id === "Room Charge" ? "→ " + roomFor(draft.spender) : m.sub}</span>
                </span>
                <span style={S.chev}>›</span>
              </button>
            ))}
          </div>
        </Section>
      )}

      {/* ----- step 3: category ----- */}
      {step === "category" && (
        <Section title="What for?" sub="Pick a category">
          <div style={S.catGrid}>
            {CATEGORIES.map((c) => {
              const on = draft.category === c.id;
              return (
                <button
                  key={c.id}
                  onClick={() => { setDraft({ ...draft, category: c.id }); setStep("amount"); }}
                  className="lift"
                  style={{
                    ...S.catCard,
                    borderColor: on ? c.color : C.line,
                    boxShadow: on ? `0 0 0 3px ${c.color}33` : S.catCard.boxShadow,
                  }}
                >
                  <span style={{ ...S.catIcon, background: c.color + "1F" }}>{c.icon}</span>
                  <span style={S.catName}>{c.id}</span>
                </button>
              );
            })}
          </div>

        </Section>
      )}

      {/* ----- step 4: amount + tip + keypad ----- */}
      {step === "amount" && (
        <AmountStep
          draft={draft} setDraft={setDraft}
          activeField={activeField} setActiveField={setActiveField}
          showTip={showTip} setShowTip={setShowTip}
          press={press} save={save}
        />
      )}

      {/* ----- saved ----- */}
      {step === "saved" && lastSaved && (
        <Saved tx={lastSaved} onAnother={reset} onTotals={goTotals} />
      )}
    </div>
  );
}

/* ---------- amount + keypad ---------- */
function AmountStep({ draft, setDraft, activeField, setActiveField, showTip, setShowTip, press, save }) {
  const S = styles;
  const bottomRef = useRef(null);
  useEffect(() => {
    const t = setTimeout(() => { if (bottomRef.current) bottomRef.current.scrollIntoView({ behavior: "smooth", block: "end" }); }, 90);
    return () => clearTimeout(t);
  }, []);
  const cat = catOf(draft.category);
  const total = draft.amountCents + draft.tipCents;
  const [showNote, setShowNote] = useState(Boolean(draft.notes) || draft.category === "Other");
  const noteRequired = draft.category === "Other";
  const blocked = draft.amountCents === 0 || (noteRequired && !draft.notes.trim());
  const keys = ["1", "2", "3", "4", "5", "6", "7", "8", "9", "00", "0", "back"];

  return (
    <Section
      title="How much?"
      sub={`${draft.spender} · ${draft.category}${draft.notes ? " · " + draft.notes : ""} · ${draft.method}${draft.method === "Room Charge" ? " → " + roomFor(draft.spender) : ""}`}
    >
      {/* amount display */}
      <button
        onClick={() => setActiveField("amount")}
        style={{ ...S.amountCard, borderColor: activeField === "amount" ? cat.color : C.line }}
      >
        <span style={S.amountLabel}>Amount</span>
        <span style={S.amountValue}>{fmt(draft.amountCents)}</span>
      </button>

      {/* tip */}
      {!showTip ? (
        <button
          onClick={() => { setShowTip(true); setActiveField("tip"); }}
          style={S.addTip}
        >＋ Add a tip</button>
      ) : (
        <button
          onClick={() => setActiveField("tip")}
          style={{ ...S.tipCard, borderColor: activeField === "tip" ? C.sun : C.line }}
        >
          <span style={S.tipLabel}>🤝 Tip</span>
          <span style={S.tipValue}>{fmt(draft.tipCents)}</span>
          <span
            role="button"
            tabIndex={0}
            onClick={(e) => { e.stopPropagation(); setDraft({ ...draft, tipCents: 0 }); setShowTip(false); setActiveField("amount"); }}
            style={S.removeTip}
          >Remove</span>
        </button>
      )}

      {showTip && (
        <div style={S.totalLine}>Total <strong style={{ color: C.ink }}>{fmt(total)}</strong></div>
      )}

      {/* note */}
      {!showNote ? (
        <button onClick={() => setShowNote(true)} style={S.addNote}>＋ Add a note</button>
      ) : (
        <input
          value={draft.notes}
          onChange={(e) => setDraft({ ...draft, notes: e.target.value })}
          placeholder={noteRequired ? "What was it? (required for Other)" : "Add a note (optional)"}
          style={{ ...S.noteInput, borderColor: noteRequired && !draft.notes.trim() ? C.coral : C.line }}
        />
      )}

      {/* keypad */}
      <div style={S.keypad}>
        {keys.map((k) => (
          <button
            key={k}
            onClick={() => press(k)}
            className="key"
            style={S.key}
            aria-label={k === "back" ? "Delete" : k}
          >{k === "back" ? "⌫" : k}</button>
        ))}
      </div>

      <button
        onClick={save}
        disabled={blocked}
        style={{ ...S.saveBtn, opacity: blocked ? 0.5 : 1 }}
      >
        Save {fmt(total)}
      </button>
      <div ref={bottomRef} style={{ height: 1 }} />
    </Section>
  );
}

/* ---------- saved confirmation ---------- */
function Saved({ tx, onAnother, onTotals }) {
  const S = styles;
  const cat = catOf(tx.category);
  const total = tx.amountCents + tx.tipCents;
  return (
    <div style={S.saved}>
      <div style={S.savedBurst}>🎉</div>
      <div style={S.savedTitle}>¡Listo!</div>
      <div style={S.savedSub}>Logged at {when(tx.ts)}</div>

      <div style={S.savedCard}>
        <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Who</span><strong>{tx.spender}</strong></div>
        <div style={S.savedRow}><span style={{ color: C.inkSoft }}>What</span><strong>{cat.icon} {tx.category}</strong></div>
        {tx.notes && <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Note</span><strong>{tx.notes}</strong></div>}
        <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Paid with</span><strong>{tx.method}</strong></div>
        {tx.room && <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Charged to</span><strong>{tx.room}</strong></div>}
        <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Amount</span><strong>{fmt(tx.amountCents)}</strong></div>
        {tx.tipCents > 0 && <div style={S.savedRow}><span style={{ color: C.inkSoft }}>Tip</span><strong>{fmt(tx.tipCents)}</strong></div>}
        <div style={{ ...S.savedRow, borderTop: `2px dashed ${C.line}`, paddingTop: 12, marginTop: 4 }}>
          <span style={{ color: C.ink, fontWeight: 800 }}>Total</span>
          <strong style={{ fontSize: 22, color: cat.color }}>{fmt(total)}</strong>
        </div>
      </div>

      <button onClick={onAnother} style={S.saveBtn}>＋ Log another</button>
      <button onClick={onTotals} style={S.ghostBtn}>View totals</button>
    </div>
  );
}

/* ============================================================
   TOTALS
   ============================================================ */
function Totals({ transactions, onDelete, onAdd }) {
  const S = styles;
  const [lens, setLens] = useState("person"); // person | category | method

  const data = useMemo(() => {
    const total = (t) => t.amountCents + t.tipCents;
    const grand = transactions.reduce((s, t) => s + total(t), 0);
    const tips = transactions.reduce((s, t) => s + t.tipCents, 0);

    const byPerson = MEMBERS.map((m) => ({
      key: m.id, color: m.color,
      total: transactions.filter((t) => t.spender === m.id).reduce((s, t) => s + total(t), 0),
    }));
    const byCategory = CATEGORIES.map((c) => ({
      key: c.id, color: c.color, icon: c.icon,
      total: transactions.filter((t) => t.category === c.id).reduce((s, t) => s + total(t), 0),
    })).filter((x) => x.total > 0).sort((a, b) => b.total - a.total);
    const byMethod = METHODS.map((m) => ({
      key: m.id, color: C.oceanDeep, icon: m.icon,
      total: transactions.filter((t) => t.method === m.id).reduce((s, t) => s + total(t), 0),
    })).filter((x) => x.total > 0);

    const roomColors = { "Lance/Lori Room": "#1E88C7", "Carter/Jett Room": "#FF7A1A" };
    const byRoom = ROOMS.map((r) => {
      const list = transactions.filter((t) => t.room === r);
      return { key: r, color: roomColors[r], total: list.reduce((s, t) => s + total(t), 0), count: list.length };
    });
    const roomGrand = byRoom.reduce((s, r) => s + r.total, 0);

    return { grand, tips, byPerson, byCategory, byMethod, byRoom, roomGrand };
  }, [transactions]);

  const rows = lens === "person" ? data.byPerson : lens === "category" ? data.byCategory : data.byMethod;
  const max = Math.max(1, ...rows.map((r) => r.total));

  if (transactions.length === 0) {
    return (
      <div style={S.empty}>
        <div style={{ fontSize: 44 }}>🏖️</div>
        <div style={S.emptyTitle}>No spends yet</div>
        <div style={S.emptySub}>Log the first one and your running totals will live right here.</div>
        <button onClick={onAdd} style={S.saveBtn}>＋ Add a spend</button>
      </div>
    );
  }

  return (
    <div>
      {/* hero total */}
      <div style={S.heroTotal}>
        <div className="sea-shimmer" style={S.heroSea} />
        <div style={S.heroInner}>
          <div style={S.heroLabel}>Trip total spent</div>
          <div style={S.heroValue}>{fmt(data.grand)}</div>
          <div style={S.heroMeta}>
            {transactions.length} {transactions.length === 1 ? "entry" : "entries"} · {fmt(data.tips)} in tips
          </div>
        </div>
      </div>

      {/* room folios */}
      {data.roomGrand > 0 && (
        <div style={S.roomWrap}>
          <div style={S.roomTitle}>🏨 Room charges <span style={S.roomTitleSub}>billed at checkout</span></div>
          <div style={S.roomGrid}>
            {data.byRoom.map((r) => (
              <div key={r.key} style={{ ...S.roomTile, borderColor: r.color }}>
                <span style={{ ...S.roomDot, background: r.color }} />
                <div style={S.roomName}>{r.key}</div>
                <div style={{ ...S.roomVal, color: r.color }}>{fmt(r.total)}</div>
                <div style={S.roomCount}>{r.count} {r.count === 1 ? "charge" : "charges"}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* lens switch */}
      <div style={S.segmented}>
        {[["person", "By person"], ["category", "By category"], ["method", "By payment"]].map(([k, label]) => (
          <button
            key={k}
            onClick={() => setLens(k)}
            style={{ ...S.seg, ...(lens === k ? S.segOn : {}) }}
          >{label}</button>
        ))}
      </div>

      {/* bars */}
      <div style={S.bars}>
        {rows.map((r) => (
          <div key={r.key} style={S.barRow}>
            <div style={S.barTop}>
              <span style={S.barName}>{r.icon ? r.icon + " " : ""}{r.key}</span>
              <span style={S.barVal}>{fmt(r.total)}</span>
            </div>
            <div style={S.barTrack}>
              <div style={{ ...S.barFill, width: `${(r.total / max) * 100}%`, background: r.color }} />
            </div>
          </div>
        ))}
      </div>

      {/* log */}
      <div style={S.logHead}>Recent</div>
      <div style={S.txList}>
        {transactions.map((t) => {
          const cat = catOf(t.category);
          const m = memOf(t.spender);
          return (
            <div key={t.id} style={S.txRow}>
              <span style={{ ...S.txIcon, background: cat.color + "1F" }}>{cat.icon}</span>
              <div style={S.txMid}>
                <div style={S.txTop}>
                  <span style={S.txCat}>{t.category}{t.notes ? ` · ${t.notes}` : ""}</span>
                  <span style={S.txAmt}>{fmt(t.amountCents + t.tipCents)}</span>
                </div>
                <div style={S.txSub}>
                  <span style={{ ...S.txWho, color: m.color }}>{t.spender}</span>
                  {" · "}{t.method}{t.room ? ` → ${t.room}` : ""}{t.tipCents > 0 ? ` · tip ${fmt(t.tipCents)}` : ""} · {when(t.ts)}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <button onClick={onAdd} style={{ ...S.saveBtn, marginTop: 18 }}>＋ Add a spend</button>
    </div>
  );
}

