/* ============================================================
   admin: PIN gate + edit-everything screen
   ============================================================ */
function PinModal({ member, expected, onClose, onResult, titleText, subText }) {
  const S = styles;
  const [entry, setEntry] = useState("");
  const [err, setErr] = useState(false);
  const color = memOf(member).color;
  const pressKey = (k) => {
    setErr(false);
    if (k === "back") { setEntry((e) => e.slice(0, -1)); return; }
    setEntry((e) => {
      const next = (e + k).slice(0, 4);
      if (next.length === 4) {
        setTimeout(() => {
          if (next === expected) onResult();
          else { setErr(true); setEntry(""); }
        }, 130);
      }
      return next;
    });
  };
  const keys = ["1", "2", "3", "4", "5", "6", "7", "8", "9", "", "0", "back"];
  return (
    <div style={S.modalWrap} onClick={onClose}>
      <div style={S.pinCard} onClick={(e) => e.stopPropagation()}>
        <span style={{ ...S.avatar, width: 108, height: 108, fontSize: 40, borderColor: color, background: memOf(member).soft, margin: "0 auto 4px" }}>
          {(memOf(member).hatPhoto || memOf(member).photo)
            ? <img src={memOf(member).hatPhoto || memOf(member).photo} alt={member} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            : <span style={{ color: "#fff" }}>{member[0]}</span>}
        </span>
        <div style={S.pinTitle}>{titleText || `${member}'s screen`}</div>
        <div style={S.pinSub}>{subText || `Enter ${member}'s 4-digit code`}</div>
        <div style={S.pinDots} className={err ? "shake" : ""}>
          {[0, 1, 2, 3].map((i) => (
            <span key={i} style={{ ...S.pinDot, ...(i < entry.length ? { background: color, borderColor: color } : {}), ...(err ? S.pinDotErr : {}) }} />
          ))}
        </div>
        {err && <div style={S.pinErr}>Wrong code — try again</div>}
        <div style={S.pinPad}>
          {keys.map((k, i) => k === "" ? <span key={i} /> : (
            <button key={i} onClick={() => pressKey(k)} className="key" style={S.pinPadKey} aria-label={k === "back" ? "Delete" : k}>
              {k === "back" ? "\u232B" : k}
            </button>
          ))}
        </div>
        <button onClick={onClose} style={S.pinCancel}>Cancel</button>
      </div>
    </div>
  );
}

function Admin({ transactions, onEdit, onDelete, onDone }) {
  const S = styles;
  return (
    <div>
      <div style={S.adminBar}>
        <div>
          <div style={S.adminTitle}>\uD83D\uDD13 Admin · edit</div>
          <div style={S.adminSub}>{transactions.length} {transactions.length === 1 ? "transaction" : "transactions"} · changes save instantly</div>
        </div>
        <button onClick={onDone} style={S.adminDone}>Done</button>
      </div>
      {transactions.length === 0 && <div style={S.adminEmpty}>No transactions yet.</div>}
      <div style={S.adminList}>
        {transactions.map((t) => <AdminRow key={t.id} t={t} onEdit={onEdit} onDelete={onDelete} />)}
      </div>
      <button onClick={onDone} style={{ ...S.saveBtn, marginTop: 18 }}>Done editing</button>
    </div>
  );
}

function AdminRow({ t, onEdit, onDelete }) {
  const S = styles;
  const dollars = (c) => (c / 100).toFixed(2);
  const toCents = (v) => Math.max(0, Math.round((parseFloat(v) || 0) * 100));
  return (
    <div style={S.adminCard}>
      <div style={S.adminGrid}>
        <label style={S.aLab}>Who
          <select value={t.spender} onChange={(e) => onEdit(t.id, { spender: e.target.value })} style={S.aSel}>
            {MEMBERS.map((m) => <option key={m.id} value={m.id}>{m.id}</option>)}
          </select>
        </label>
        <label style={S.aLab}>Paid with
          <select value={t.method} onChange={(e) => onEdit(t.id, { method: e.target.value })} style={S.aSel}>
            {METHODS.map((m) => <option key={m.id} value={m.id}>{m.id}</option>)}
          </select>
        </label>
        <label style={{ ...S.aLab, gridColumn: "1 / -1" }}>Category
          <select value={t.category} onChange={(e) => onEdit(t.id, { category: e.target.value })} style={S.aSel}>
            {CATEGORIES.map((c) => <option key={c.id} value={c.id}>{c.id}</option>)}
          </select>
        </label>
        <label style={S.aLab}>Amount $
          <input type="number" step="0.01" inputMode="decimal" defaultValue={dollars(t.amountCents)}
            onBlur={(e) => onEdit(t.id, { amountCents: toCents(e.target.value) })} style={S.aInp} />
        </label>
        <label style={S.aLab}>Tip $
          <input type="number" step="0.01" inputMode="decimal" defaultValue={dollars(t.tipCents)}
            onBlur={(e) => onEdit(t.id, { tipCents: toCents(e.target.value) })} style={S.aInp} />
        </label>
        <label style={{ ...S.aLab, gridColumn: "1 / -1" }}>Note
          <input defaultValue={t.notes || ""} placeholder="\u2014"
            onBlur={(e) => onEdit(t.id, { notes: e.target.value })} style={S.aInp} />
        </label>
      </div>
      <div style={S.adminFoot}>
        <span style={S.adminMeta}>{t.room ? t.room + " · " : ""}{when(t.ts)}</span>
        <button onClick={() => onDelete(t.id)} style={S.adminDel}>Delete</button>
      </div>
    </div>
  );
}

