const css = `
@import url('https://fonts.googleapis.com/css2?family=Baloo+2:wght@500;600;700;800&family=Nunito:wght@400;600;700;800&display=swap');
* { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
button { border: none; background: none; cursor: pointer; font-family: inherit; }
:focus-visible { outline: 3px solid ${C.oceanDeep}; outline-offset: 2px; }
.lift { transition: transform .12s ease, box-shadow .12s ease; }
.lift:active { transform: scale(.97); }
.key:active { transform: translateY(2px); box-shadow: 0 1px 0 ${C.line}; }
.sea-shimmer { background-image: linear-gradient(110deg, #ffffff00 30%, #ffffff55 50%, #ffffff00 70%); background-size: 220% 100%; animation: shimmer 4.5s linear infinite; }
@keyframes shimmer { 0% { background-position: 200% 0; } 100% { background-position: -120% 0; } }
@keyframes shake { 0%,100% { transform: translateX(0); } 20%,60% { transform: translateX(-7px); } 40%,80% { transform: translateX(7px); } }
.shake { animation: shake .35s; }
@media (prefers-reduced-motion: reduce) { .sea-shimmer { animation: none; } .lift { transition: none; } }
input::placeholder { color: #B9C7C9; }
`;
